def expand_dims(x: Array, /, *, axis: int = 0) -> Array:
    if not -x.ndim - 1 <= axis <= x.ndim:
        raise IndexError(
            "'axis' must be within `[-{x.ndim}-1, {x.ndim}]`, found `{axis}`"
        )
    if axis < 0:
        axis = x.ndim + axis + 1
    key = tuple(None if el == axis else slice(None, None) for el in range(x.ndim + 1))
    return x[key]

def finfo(ty: DType | Array, /):
    if isinstance(ty, Array):
        ty = ty.dtype
    if nde.is_nullable_float_dtype(ty):
        npdtype = ty._unmasked_dtype.unwrap_numpy()
    elif nde.is_float_dtype(ty):
        npdtype = ty.unwrap_numpy()
    else:
        raise ValueError(f"'FIinfo' not available for type `{ty}`")
    finfo = np.finfo(npdtype)
    return Finfo(
        bits=finfo.bits,
        max=float(finfo.max),
        min=float(finfo.min),
        dtype=ty,
        smallest_normal=float(finfo.smallest_normal),
        eps=float(finfo.eps),
    )

def flip(x: Array, /, *, axis: int | tuple[int, ...] | None = None) -> Array:
    if axis is None:
        index = [slice(None, None, -1) for _ in range(x.ndim)]
    else:
        index = [slice(None, None, 1) for _ in range(x.ndim)]
        if isinstance(axis, int):
            axis = (axis,)
        for ax in axis:
            index[ax] = slice(None, None, -1)
    return x[tuple(index)]

